import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { CreditCard, Smartphone, Building2, Lock, CheckCircle } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { toast } from 'react-toastify';
import '../assets/styles/Payment.css';

const API_BASE = 'http://localhost:5000';

const UPI_APPS = [
  { id: 'gpay',    label: 'Google Pay', emoji: '🟦' },
  { id: 'phonepe', label: 'PhonePe',    emoji: '🟣' },
  { id: 'paytm',   label: 'Paytm',      emoji: '🔵' },
];

const BANKS = [
  { code: 'SBI',   name: 'State Bank of India' },
  { code: 'HDFC',  name: 'HDFC Bank' },
  { code: 'ICICI', name: 'ICICI Bank' },
  { code: 'AXIS',  name: 'Axis Bank' },
  { code: 'KOTAK', name: 'Kotak Mahindra' },
];

/* ─── Helpers ─────────────────────────────────────────────── */
const formatCardNumber = (val) =>
  val.replace(/\D/g, '').slice(0, 16).replace(/(.{4})/g, '$1 ').trim();

const formatExpiry = (val) => {
  const digits = val.replace(/\D/g, '').slice(0, 4);
  if (digits.length <= 2) return digits;
  return `${digits.slice(0, 2)}/${digits.slice(2)}`;
};

const formatCvv = (val) => val.replace(/\D/g, '').slice(0, 3);

const Payment = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { cartItems, cartTotal, clearCart } = useCart();
  const addressId = location.state?.addressId;

  const [paymentTab, setPaymentTab] = useState('upi');
  const [selectedUpiApp, setSelectedUpiApp] = useState(null);
  const [upiId, setUpiId] = useState('');
  const [cardData, setCardData] = useState({ number: '', name: '', expiry: '', cvv: '' });
  const [cardErrors, setCardErrors] = useState({});
  const [selectedBank, setSelectedBank] = useState('SBI');
  const [processing, setProcessing] = useState(false);

  const deliveryFee = cartTotal > 500 ? 0 : 49;
  const finalTotal = cartTotal + deliveryFee;

  const getAuthHeaders = () => ({
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${localStorage.getItem('token')}`
  });

  /* ─── Load Razorpay Script ─────────────────────────────── */
  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://checkout.razorpay.com/v1/checkout.js';
    script.async = true;
    document.body.appendChild(script);
    return () => document.body.removeChild(script);
  }, []);

  /* ─── Card Validation ──────────────────────────────────── */
  const validateCard = () => {
    const errors = {};
    const rawNum = cardData.number.replace(/\s/g, '');
    if (rawNum.length !== 16) errors.number = 'Card number must be 16 digits';
    if (!cardData.name.trim()) errors.name = 'Cardholder name is required';
    const [mm, yy] = cardData.expiry.split('/');
    const month = parseInt(mm, 10);
    const year = parseInt('20' + yy, 10);
    const now = new Date();
    if (!mm || !yy || mm.length !== 2 || yy.length !== 2 || month < 1 || month > 12
        || year < now.getFullYear()
        || (year === now.getFullYear() && month < now.getMonth() + 1)) {
      errors.expiry = 'Enter a valid future date (MM/YY)';
    }
    if (cardData.cvv.length !== 3) errors.cvv = 'CVV must be exactly 3 digits';
    setCardErrors(errors);
    return Object.keys(errors).length === 0;
  };

  /* ─── Place Order (Mock success after Razorpay / UPI) ──── */
  const placeOrder = async (paymentMethod) => {
    try {
      const res = await fetch(`${API_BASE}/api/order`, {
        method: 'POST',
        headers: getAuthHeaders(),
        body: JSON.stringify({ addressId, paymentMethod })
      });
      const data = await res.json();
      if (data.success) {
        await clearCart();
        navigate('/order-success', { state: { order: data.order } });
      } else {
        toast.error(data.message || 'Order placement failed.');
        setProcessing(false);
      }
    } catch {
      toast.error('Could not connect to server. Please retry.');
      setProcessing(false);
    }
  };

  /* ─── Razorpay Flow ──────────────────────────────────────── */
  const openRazorpay = async (method) => {
    if (!window.Razorpay) {
      toast.error('Payment SDK not loaded. Check internet connection.');
      return;
    }

    setProcessing(true);
    try {
      const res = await fetch(`${API_BASE}/api/payment/create-order`, {
        method: 'POST',
        headers: getAuthHeaders()
      });
      const data = await res.json();

      if (!data.success) {
        // Fallback: if Razorpay key fails, do simulated payment
        toast.info('Simulating payment (no Razorpay key configured)...');
        setTimeout(() => placeOrder(method.toUpperCase()), 2000);
        return;
      }

      const options = {
        key: data.keyId,
        amount: data.amount,
        currency: data.currency,
        name: 'JaggryWeApp Heritage Harvest',
        description: 'Artisanal Products',
        order_id: data.orderId,
        theme: { color: '#D4A373' },
        modal: {
          ondismiss: () => { toast.info('Payment cancelled. Cart is safe.'); setProcessing(false); }
        },
        handler: async (response) => {
          try {
            const vRes = await fetch(`${API_BASE}/api/payment/verify`, {
              method: 'POST',
              headers: getAuthHeaders(),
              body: JSON.stringify({
                razorpay_order_id: response.razorpay_order_id,
                razorpay_payment_id: response.razorpay_payment_id,
                razorpay_signature: response.razorpay_signature,
                addressId
              })
            });
            const vData = await vRes.json();
            if (vData.success) {
              await clearCart();
              navigate('/order-success', { state: { order: vData.order } });
            } else {
              toast.error(vData.message);
              setProcessing(false);
            }
          } catch {
            toast.error('Verification failed. Contact support.');
            setProcessing(false);
          }
        }
      };

      const rzp = new window.Razorpay(options);
      rzp.on('payment.failed', (err) => {
        toast.error(`Payment failed: ${err.error.description}`);
        setProcessing(false);
      });
      rzp.open();
    } catch {
      // If backend is down, simulate for dev testing
      toast.info('Backend unavailable — simulating payment...');
      setTimeout(() => placeOrder(method.toUpperCase()), 2000);
    }
  };

  /* ─── Handle Pay Button ──────────────────────────────────── */
  const handlePay = () => {
    if (!addressId) {
      toast.error('No delivery address. Go back to checkout.');
      return;
    }
    if (!localStorage.getItem('token')) {
      toast.error('Please log in to complete payment.');
      return;
    }

    if (paymentTab === 'upi') {
      if (!selectedUpiApp && !upiId.includes('@')) {
        toast.error('Select a UPI app or enter a valid UPI ID');
        return;
      }
      openRazorpay('upi');

    } else if (paymentTab === 'card') {
      if (!validateCard()) {
        toast.error('Please fix the card errors highlighted below.');
        return;
      }
      openRazorpay('card');

    } else {
      setProcessing(true);
      toast.info(`Redirecting to ${selectedBank} Net Banking...`);
      setTimeout(() => placeOrder('NETBANKING'), 2000);
    }
  };

  /* ─── Render ─────────────────────────────────────────────── */
  return (
    <div className="payment-page">
      <div className="payment-container">

        {/* Test Credentials Banner */}
        <div className="test-credentials-banner">
          <strong>🧪 Test Mode</strong>
          <span>UPI: <code>success@razorpay</code></span>
          <span>Card: <code>4111 1111 1111 1111</code> · Expiry: <code>12/26</code> · CVV: <code>123</code> · OTP: <code>1234</code></span>
        </div>

        <div className="payment-grid">
          {/* ── Left Panel ── */}
          <div className="payment-methods-panel">
            <div className="payment-header">
              <Lock size={16} />
              <h2>Secure Payment</h2>
            </div>

            <div className="payment-tabs">
              {[
                { id: 'upi', label: 'UPI', Icon: Smartphone },
                { id: 'card', label: 'Card', Icon: CreditCard },
                { id: 'netbanking', label: 'Net Banking', Icon: Building2 },
              ].map(({ id, label, Icon }) => (
                <button key={id} type="button"
                  className={`pay-tab ${paymentTab === id ? 'active' : ''}`}
                  onClick={() => setPaymentTab(id)}>
                  <Icon size={16} /> {label}
                </button>
              ))}
            </div>

            {/* UPI */}
            {paymentTab === 'upi' && (
              <div className="pay-form">
                <h3>Pay via UPI</h3>
                <p className="pay-hint">Select an app or enter your UPI ID</p>
                <div className="upi-apps">
                  {UPI_APPS.map(app => (
                    <button key={app.id} type="button"
                      className={`upi-app-btn ${selectedUpiApp === app.id ? 'selected' : ''}`}
                      onClick={() => { setSelectedUpiApp(app.id); setUpiId(''); }}>
                      <span className="upi-emoji">{app.emoji}</span>
                      <span>{app.label}</span>
                      {selectedUpiApp === app.id && <CheckCircle size={14} className="upi-check" />}
                    </button>
                  ))}
                </div>
                <div className="pay-divider"><span>or enter UPI ID</span></div>
                <label>UPI ID</label>
                <input type="text" placeholder="yourname@upi  (test: success@razorpay)"
                  value={upiId}
                  onChange={e => { setUpiId(e.target.value); setSelectedUpiApp(null); }} />
              </div>
            )}

            {/* Card */}
            {paymentTab === 'card' && (
              <div className="pay-form">
                <h3>Pay via Card</h3>
                <p className="pay-hint">Debit or Credit Card · Test: 4111 1111 1111 1111</p>

                <label>Card Number</label>
                <input type="text" placeholder="4111 1111 1111 1111"
                  value={cardData.number}
                  onChange={e => setCardData({ ...cardData, number: formatCardNumber(e.target.value) })}
                  className={cardErrors.number ? 'input-error' : ''} />
                {cardErrors.number && <span className="field-error">{cardErrors.number}</span>}

                <label>Cardholder Name</label>
                <input type="text" placeholder="Name as on card"
                  value={cardData.name}
                  onChange={e => setCardData({ ...cardData, name: e.target.value })}
                  className={cardErrors.name ? 'input-error' : ''} />
                {cardErrors.name && <span className="field-error">{cardErrors.name}</span>}

                <div className="card-row">
                  <div>
                    <label>Expiry (MM/YY)</label>
                    <input type="text" placeholder="MM/YY" maxLength={5}
                      value={cardData.expiry}
                      onChange={e => setCardData({ ...cardData, expiry: formatExpiry(e.target.value) })}
                      className={cardErrors.expiry ? 'input-error' : ''} />
                    {cardErrors.expiry && <span className="field-error">{cardErrors.expiry}</span>}
                  </div>
                  <div>
                    <label>CVV (3 digits)</label>
                    <input type="password" placeholder="•••" maxLength={3}
                      inputMode="numeric"
                      value={cardData.cvv}
                      onChange={e => setCardData({ ...cardData, cvv: formatCvv(e.target.value) })}
                      className={cardErrors.cvv ? 'input-error' : ''} />
                    {cardErrors.cvv && <span className="field-error">{cardErrors.cvv}</span>}
                  </div>
                </div>
              </div>
            )}

            {/* Net Banking */}
            {paymentTab === 'netbanking' && (
              <div className="pay-form">
                <h3>Net Banking</h3>
                <p className="pay-hint">You will be redirected to your bank's secure portal</p>
                <label>Select your bank</label>
                <select value={selectedBank} onChange={e => setSelectedBank(e.target.value)}>
                  {BANKS.map(b => <option key={b.code} value={b.code}>{b.name}</option>)}
                </select>
              </div>
            )}
          </div>

          {/* ── Right Panel ── */}
          <div className="payment-summary-panel">
            <h3>Order Summary</h3>
            <div className="pay-summary-items">
              {cartItems.map(item => (
                <div key={item.itemId} className="pay-summary-row">
                  <span>{item.title}{item.weight ? ` (${item.weight})` : ''} × {item.quantity}</span>
                  <span>₹{(item.price * item.quantity).toFixed(2)}</span>
                </div>
              ))}
            </div>
            <div className="pay-total-rows">
              <div className="pay-total-row"><span>Subtotal</span><span>₹{cartTotal.toFixed(2)}</span></div>
              <div className="pay-total-row">
                <span>Delivery</span>
                <span className={deliveryFee === 0 ? 'free-tag' : ''}>{deliveryFee === 0 ? '🎉 FREE' : `₹${deliveryFee}`}</span>
              </div>
              <div className="pay-total-row grand"><span>Total</span><span>₹{finalTotal.toFixed(2)}</span></div>
            </div>

            <button type="button" className="pay-now-btn" onClick={handlePay} disabled={processing}>
              {processing
                ? <span className="paying-spinner"><span className="spinner-dot"></span> Processing...</span>
                : `Pay ₹${finalTotal.toFixed(2)}`}
            </button>
            <p className="secure-note"><Lock size={12} /> 256-bit SSL · Powered by Razorpay</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Payment;
